from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["final-install-use-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>God Mode Install & Use Now</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--bad:#ef4444}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:8px}button{font:inherit;border-radius:16px;border:0;background:linear-gradient(135deg,#0284c7,#38bdf8);color:#02101b;padding:12px;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}.score{font-size:46px;font-weight:1000}.item{border-left:4px solid var(--ok);padding:9px 10px;background:#081226;border-radius:14px}.bad{border-left-color:var(--bad)}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}.score{font-size:34px}}</style></head><body><div class="page"><section class="panel"><h1>God Mode Install & Use Now</h1><p class="muted">Página final para instalar, ligar PC/APK e iniciar o primeiro uso real.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/artifacts-center'" class="dark">Artifacts</button><button onclick="location.href='/app/connect-phone'" class="dark">Connect Phone</button><button onclick="location.href='/app/today-ready'" class="dark">Today Ready</button><button onclick="location.href='/app/god-mode-vault'" class="dark">Vault</button><button onclick="loadPack()">Refresh</button><button onclick="startNow()">Start Now</button></div></section><section class="panel"><h2>Final readiness</h2><div id="score" class="score">...</div></section><section class="panel"><h2>Checks</h2><div id="checks" class="grid"></div></section><section class="panel"><h2>PC steps</h2><div id="pcsteps" class="grid"></div></section><section class="panel"><h2>Phone/APK steps</h2><div id="phonesteps" class="grid"></div></section><section class="panel"><h2>APK endpoint contract</h2><div id="endpoints" class="grid"></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const r=x?.readiness||x; qs('#score').textContent=(r?.final_ready_score??x?.status?.final_ready_score??'...')+'%'; const checks=r?.checks||[]; qs('#checks').innerHTML=checks.map(c=>`<div class="item ${c.ok?'':'bad'}"><b>${esc(c.name)}</b><br>${c.ok?'OK':'FAIL'}<br><span class="muted">${esc(c.route)}</span></div>`).join(''); const pc=x?.install_steps?.pc||[]; qs('#pcsteps').innerHTML=pc.map(s=>`<div class="item"><b>${esc(s.step)}. ${esc(s.title)}</b><br><span class="muted">${esc(s.action)}</span></div>`).join(''); const ph=x?.install_steps?.phone||[]; qs('#phonesteps').innerHTML=ph.map(s=>`<div class="item"><b>${esc(s.step)}. ${esc(s.title)}</b><br><span class="muted">${esc(s.action)}</span></div>`).join(''); const eps=x?.apk_endpoint_contract?.mobile_should_try_in_order||[]; qs('#endpoints').innerHTML=eps.slice(0,18).map(e=>`<div class="item"><b>${esc(e.mode)}</b><br><span class="muted">${esc(e.url)}</span></div>`).join('')}async function loadPack(){show(await api('/api/final-install-use/package'))}async function startNow(){show(await api('/api/final-install-use/start-now',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({tenant_id:'owner-andre'})}))}loadPack()</script></body></html>
"""


@router.get('/app/install-use-now', response_class=HTMLResponse)
async def install_use_now_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/final-ready', response_class=HTMLResponse)
async def final_ready_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
